{
  "name": "@lightfastai/cli",
  "version": "0.1.0",
  "description": "Lightfast CLI - command-line tools for the Lightfast platform",
  "publishConfig": {
    "tag": "latest",
    "access": "public"
  },
  "keywords": [
    "lightfast",
    "cli",
    "ai",
    "platform",
    "developer-tools"
  ],
  "repository": {
    "type": "git",
    "url": "https://github.com/lightfastai/lightfast.git",
    "directory": "core/cli"
  },
  "homepage": "https://lightfast.ai",
  "bugs": "https://github.com/lightfastai/lightfast/issues",
  "license": "MIT",
  "author": "Lightfast <hello@lightfast.ai>",
  "type": "module",
  "bin": {
    "lightfast": "./dist/bin.mjs"
  },
  "main": "./dist/index.mjs",
  "types": "./dist/index.d.ts",
  "exports": {
    ".": {
      "types": "./dist/index.d.ts",
      "import": "./dist/index.mjs"
    }
  },
  "files": [
    "dist"
  ],
  "scripts": {
    "build": "tsup",
    "clean": "rm -rf dist .cache .turbo node_modules",
    "dev": "tsup --watch",
    "typecheck": "tsc --noEmit"
  },
  "dependencies": {
    "@inquirer/select": "^4.0.0",
    "@t3-oss/env-core": "catalog:",
    "commander": "^13.1.0",
    "eventsource-parser": "^3.0.7",
    "open": "^10.1.0",
    "ora": "^8.1.1",
    "picocolors": "^1.1.0",
    "zod": "catalog:"
  },
  "devDependencies": {
    "@repo/typescript-config": "workspace:*",
    "@types/node": "catalog:",
    "tsup": "^8.5.1",
    "typescript": "catalog:"
  },
  "engines": {
    "node": ">=22"
  }
}

{
  "name": "@repo/app-octokit-github",
  "license": "Apache-2.0",
  "version": "0.1.0",
  "private": true,
  "type": "module",
  "sideEffects": false,
  "exports": {
    ".": {
      "types": "./src/index.ts",
      "default": "./src/index.ts"
    },
    "./env": {
      "types": "./src/env.ts",
      "default": "./src/env.ts"
    }
  },
  "scripts": {
    "clean": "git clean -xdf .cache .turbo node_modules",
    "typecheck": "tsc --noEmit"
  },
  "dependencies": {
    "@octokit/openapi-types": "^26.0.0",
    "@octokit/plugin-retry": "^8.1.0",
    "@octokit/plugin-throttling": "^11.0.3",
    "@t3-oss/env-nextjs": "catalog:",
    "octokit": "^5.0.5",
    "zod": "catalog:"
  },
  "devDependencies": {
    "@repo/typescript-config": "workspace:*",
    "@types/node": "catalog:",
    "typescript": "catalog:"
  }
}

{
  "name": "@vendor/seo",
  "license": "MIT",
  "version": "0.0.0",
  "private": true,
  "type": "module",
  "sideEffects": false,
  "exports": {
    "./env": {
      "types": "./src/env.ts",
      "default": "./src/env.ts"
    },
    "./json-ld": {
      "types": "./src/json-ld.tsx",
      "default": "./src/json-ld.tsx"
    },
    "./metadata": {
      "types": "./src/metadata.ts",
      "default": "./src/metadata.ts"
    }
  },
  "scripts": {
    "clean": "git clean -xdf .cache .turbo dist node_modules",
    "typecheck": "tsc --noEmit"
  },
  "dependencies": {
    "@t3-oss/env-nextjs": "catalog:",
    "react": "catalog:react19",
    "schema-dts": "^1.1.5",
    "zod": "catalog:"
  },
  "devDependencies": {
    "@repo/typescript-config": "workspace:*",
    "@types/node": "catalog:",
    "@types/react": "catalog:react19",
    "next": "catalog:next16",
    "typescript": "catalog:"
  }
}

