{
  "name": "@vendor/security",
  "private": true,
  "version": "0.1.0",
  "type": "module",
  "sideEffects": false,
  "exports": {
    ".": {
      "types": "./src/index.ts",
      "default": "./src/index.ts"
    },
    "./env": {
      "types": "./src/env.ts",
      "default": "./src/env.ts"
    },
    "./middleware": {
      "types": "./src/middleware.ts",
      "default": "./src/middleware.ts"
    },
    "./clerk-nosecone": {
      "types": "./src/clerk-nosecone.ts",
      "default": "./src/clerk-nosecone.ts"
    },
    "./csp": {
      "types": "./src/csp/index.ts",
      "default": "./src/csp/index.ts"
    }
  },
  "license": "MIT",
  "scripts": {
    "clean": "git clean -xdf .cache .turbo node_modules",
    "typecheck": "tsc --noEmit"
  },
  "devDependencies": {
    "@repo/typescript-config": "workspace:*",
    "nosecone": "1.0.0-beta.15",
    "typescript": "catalog:"
  },
  "dependencies": {
    "@arcjet/decorate": "1.0.0-beta.10",
