2	import langBash from "@shikijs/langs/bash";
3	import langCss from "@shikijs/langs/css";
4	import langGo from "@shikijs/langs/go";
5	import langHtml from "@shikijs/langs/html";
6	import langJs from "@shikijs/langs/javascript";
7	import langJson from "@shikijs/langs/json";
8	import langJsonc from "@shikijs/langs/jsonc";
9	import langJsx from "@shikijs/langs/jsx";
10	import langMarkdown from "@shikijs/langs/markdown";
11	import langPy from "@shikijs/langs/python";
12	import langRust from "@shikijs/langs/rust";
13	import langSql from "@shikijs/langs/sql";
14	import langTsx from "@shikijs/langs/tsx";
15	import langTs from "@shikijs/langs/typescript";
16	import langYaml from "@shikijs/langs/yaml";
17	import githubLightDefault from "@shikijs/themes/github-light-default";
18	import { toJsxRuntime } from "hast-util-to-jsx-runtime";
19	import { Fragment } from "react";
20	import { jsx, jsxs } from "react/jsx-runtime";
21	import type { BundledLanguage } from "shiki";
22	import type { HighlighterCore } from "shiki/core";
23	import { createHighlighterCore } from "shiki/core";
24	import { createJavaScriptRegexEngine } from "shiki/engine/javascript";
25	import { SSRCodeBlockCopyButton } from "./copy-button";
26	import { openaiDark } from "./openai-dark-theme";
27	
28	// Singleton highlighter — initialized once, reused across all SSR renders
29	let _highlighterPromise: Promise<HighlighterCore> | null = null;
30	
31	function getHighlighter(): Promise<HighlighterCore> {
32	  if (!_highlighterPromise) {
33	    _highlighterPromise = createHighlighterCore({
34	      themes: [githubLightDefault, openaiDark],
35	      langs: [
36	        langTs,
37	        langJs,
38	        langTsx,
39	        langJsx,
40	        langBash,
41	        langJson,
42	        langJsonc,
43	        langYaml,
44	        langPy,
45	        langGo,
46	        langRust,
47	        langSql,
48	        langCss,
49	        langHtml,
50	        langMarkdown,
51	      ],
52	      engine: createJavaScriptRegexEngine(),
53	    });
54	  }
55	  return _highlighterPromise;
56	}
57	
58	// Re-export types for consumers
59	export type { BundledLanguage, BundledTheme } from "shiki";
60	
61	interface SSRCodeBlockProps {
62	  children: string;
63	  className?: string;
64	  language?: string;
65	  showHeader?: boolean;
66	}
67	
68	export async function SSRCodeBlock({
69	  children,
70	  language = "typescript",
71	  className,
72	  showHeader = true,
73	}: SSRCodeBlockProps) {
74	  const code = children.trim();
75	
76	  // Normalize language names - handle common aliases and invalid languages
77	  let lang: BundledLanguage = language as BundledLanguage;
78	  const languageLower = language.toLowerCase();
79	
80	  // Map common invalid/alias names to valid Shiki languages
81	  const languageMap: Record<string, BundledLanguage> = {
82	    plaintext: "plaintext" as BundledLanguage,
83	    plain: "plaintext" as BundledLanguage,
84	  };
85	
86	  const mappedLang = languageMap[languageLower];
87	  if (mappedLang) {
88	    lang = mappedLang;
89	  }
90	
91	  // Type for HAST tree nodes, extracted from toJsxRuntime's expected parameter
92	  type HastNodes = Parameters<typeof toJsxRuntime>[0];
93	
94	  // Generate HAST for both themes in parallel, with fallback to plain text
95	  const hl = await getHighlighter();
96	  let lightHast: HastNodes;
97	  let darkHast: HastNodes;
98	  try {
99	    [lightHast, darkHast] = (await Promise.all([
100	      hl.codeToHast(code, {
101	        lang,
102	        theme: "github-light-default",
103	      }),
104	      hl.codeToHast(code, {
105	        lang,
106	        theme: "openai-dark",
107	      }),
108	    ])) as [HastNodes, HastNodes];
109	  } catch {
110	    // If language is not supported, fall back to plain text
111	    [lightHast, darkHast] = (await Promise.all([
112	      hl.codeToHast(code, {
113	        lang: "text",
114	        theme: "github-light-default",
115	      }),
116	      hl.codeToHast(code, {
117	        lang: "text",
118	        theme: "openai-dark",
119	      }),
120	    ])) as [HastNodes, HastNodes];
121	  }
122	
123	  // Convert HAST to JSX for both themes
124	  // Override elements to control styling while preserving Shiki's syntax colors
125	  // IMPORTANT: leading-[1.7] must be set here directly because the className overrides parent styles
126	  const createShikiComponents = (mode: "light" | "dark") => ({
127	    pre: ({
128	      style: _style,
129	      ...props
130	    }: {
131	      style?: React.CSSProperties;
132	      [key: string]: unknown;
133	    }) => (
134	      <pre
135	        {...props}
136	        className="m-0 border-0 bg-transparent p-0 leading-[1.7]! tracking-normal"
137	      />
138	    ),
139	    code: ({
140	      style: _style,
141	      ...props
142	    }: {
143	      style?: React.CSSProperties;
144	      [key: string]: unknown;
145	    }) => <code {...props} className="block leading-[1.7]!" />,
146	    // Ensure spans have visible text color - use Shiki's color if provided, else fallback
147	    span: ({
148	      style,
149	      ...props
150	    }: {
151	      style?: React.CSSProperties;
152	      [key: string]: unknown;
153	    }) => {
154	      const colorValue = style?.color;
155	      const hasColor = colorValue && colorValue !== "inherit";
156	      const fallbackColor = mode === "light" ? "#24292e" : "#dcdcdc";
157	      return (
158	        <span
159	          {...props}
160	          className="leading-[1.7]!"
161	          style={{
162	            ...style,
163	            color: hasColor ? colorValue : fallbackColor,
164	            letterSpacing: "normal",
165	          }}
166	        />
167	      );
168	    },
169	  });
170	
171	  function hastToJsx(hast: HastNodes, mode: "light" | "dark"): React.ReactNode {
172	    // toJsxRuntime types depend on the `hast` module which eslint's type checker
173	    // cannot fully resolve, requiring the explicit cast here
174	    return toJsxRuntime(hast, {
175	      Fragment,
176	      jsx,
177	      jsxs,
178	      components: createShikiComponents(mode),
179	    } as Parameters<typeof toJsxRuntime>[1]) as React.ReactNode;
180	  }
181	
182	  const lightJsx = hastToJsx(lightHast, "light");
183	  const darkJsx = hastToJsx(darkHast, "dark");
184	
185	  return (
186	    <div className={cn("my-4", className)}>
187	      <div className="scrollbar-thin overflow-hidden rounded-sm dark:bg-card/80">
188	        {/* Header with language label and copy button */}
189	        {showHeader && (
190	          <div className="flex items-center justify-between py-2 pr-3 pl-6">
191	            <span className="font-medium font-mono text-muted-foreground text-xs">
192	              {language}
193	            </span>
194	            <SSRCodeBlockCopyButton code={code} />
195	          </div>
196	        )}
197	
198	        {/* Code content with line numbers */}
199	        <div className="overflow-x-auto px-6 pb-4">
200	          <div className="flex min-w-max">
201	            {/* Code content - dual theme rendering */}
202	            {/* text-foreground provides base color for plain text (no syntax highlighting) */}
203	            <div className="flex-1 text-foreground">
204	              {/* Light theme - hidden in dark mode */}
205	              <div className="block font-mono text-xs dark:hidden">
206	                {lightJsx}
207	              </div>
208	              {/* Dark theme - hidden in light mode */}
209	              <div className="hidden font-mono text-sm dark:block">
210	                {darkJsx}
211	              </div>
212	            </div>
213	          </div>
214	        </div>
215	      </div>
216	    </div>
217	  );
218	}
219	
220	// Re-export the copy button for consumers who need it separately
221	export { SSRCodeBlockCopyButton } from "./copy-button";
